// Auth0 Organizations Management Service
let cachedToken = null;
let tokenExpiry = null;

const getManagementToken = async () => {
  // Return cached token if still valid
  if (cachedToken && tokenExpiry && Date.now() < tokenExpiry) {
    return cachedToken;
  }

  const domain = process.env.REACT_APP_AUTH0_DOMAIN;
  const clientId = process.env.REACT_APP_AUTH0_M2M_CLIENT_ID;
  const clientSecret = process.env.REACT_APP_AUTH0_M2M_CLIENT_SECRET;

  if (!domain || !clientId || !clientSecret) {
    throw new Error('Auth0 M2M credentials not configured');
  }

  try {
    const response = await fetch(`https://${domain}/oauth/token`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        client_id: clientId,
        client_secret: clientSecret,
        audience: `https://${domain}/api/v2/`,
        grant_type: 'client_credentials',
      }),
    });

    if (!response.ok) {
      throw new Error('Failed to get management token');
    }

    const data = await response.json();
    cachedToken = data.access_token;
    tokenExpiry = Date.now() + (data.expires_in * 1000) - 60000; // Refresh 1 min before expiry
    return cachedToken;
  } catch (error) {
    console.error('Token error:', error);
    throw error;
  }
};

export const createOrganization = async (name, displayName) => {
  const token = await getManagementToken();
  const domain = process.env.REACT_APP_AUTH0_DOMAIN;

  try {
    const response = await fetch(`https://${domain}/api/v2/organizations`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        name,
        display_name: displayName,
      }),
    });

    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.message || 'Failed to create organization');
    }

    return await response.json();
  } catch (error) {
    console.error('Create org error:', error);
    throw error;
  }
};

export const getOrganizations = async () => {
  const token = await getManagementToken();
  const domain = process.env.REACT_APP_AUTH0_DOMAIN;

  try {
    const response = await fetch(`https://${domain}/api/v2/organizations`, {
      headers: {
        'Authorization': `Bearer ${token}`,
      },
    });

    if (!response.ok) {
      throw new Error('Failed to get organizations');
    }

    const data = await response.json();
    return data.organizations || [];
  } catch (error) {
    console.error('Get orgs error:', error);
    throw error;
  }
};

export const inviteUserToOrganization = async (organizationId, email, roles = []) => {
  const token = await getManagementToken();
  const domain = process.env.REACT_APP_AUTH0_DOMAIN;

  try {
    const response = await fetch(
      `https://${domain}/api/v2/organizations/${organizationId}/members/invitations`,
      {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          invitee_email: email,
          inviter_name: 'Guardy AI',
          send_invitation_email: true,
          client_id: process.env.REACT_APP_AUTH0_CLIENT_ID,
          roles,
        }),
      }
    );

    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.message || 'Failed to invite user');
    }

    return await response.json();
  } catch (error) {
    console.error('Invite error:', error);
    throw error;
  }
};

export const getOrganizationMembers = async (organizationId) => {
  const token = await getManagementToken();
  const domain = process.env.REACT_APP_AUTH0_DOMAIN;

  try {
    const response = await fetch(
      `https://${domain}/api/v2/organizations/${organizationId}/members`,
      {
        headers: {
          'Authorization': `Bearer ${token}`,
        },
      }
    );

    if (!response.ok) {
      throw new Error('Failed to get members');
    }

    const data = await response.json();
    return data.members || [];
  } catch (error) {
    console.error('Get members error:', error);
    throw error;
  }
};

export const removeOrganizationMember = async (organizationId, userId) => {
  const token = await getManagementToken();
  const domain = process.env.REACT_APP_AUTH0_DOMAIN;

  try {
    const response = await fetch(
      `https://${domain}/api/v2/organizations/${organizationId}/members/${userId}`,
      {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${token}`,
        },
      }
    );

    if (!response.ok) {
      throw new Error('Failed to remove member');
    }

    return true;
  } catch (error) {
    console.error('Remove member error:', error);
    throw error;
  }
};

export const getUserOrganizations = async (userId) => {
  const token = await getManagementToken();
  const domain = process.env.REACT_APP_AUTH0_DOMAIN;

  try {
    const response = await fetch(
      `https://${domain}/api/v2/users/${userId}/organizations`,
      {
        headers: {
          'Authorization': `Bearer ${token}`,
        },
      }
    );

    if (!response.ok) {
      throw new Error('Failed to get user organizations');
    }

    const data = await response.json();
    return data.organizations || [];
  } catch (error) {
    console.error('Get user orgs error:', error);
    throw error;
  }
};
